"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 27–28
Run: python3 scripts/zc-christ-genesis-27-28.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (existing: chs 1–26 complete)

Key Christological decisions:
- Ch27 blessing-by-deception: handled honestly — the deception is real, not
  commended, yet the blessing is the covenant blessing. Two key typological
  connections: (1) Jacob clothed in Esau's garments to receive Esau's blessing
  = believers clothed in Christ's righteousness to receive the Father's blessing
  (Isa 61:10; Gal 3:27); (2) Rebekah's offer "let the curse fall on me" (v13)
  and the goatskin covering of Jacob's hands (v16) foreshadow Gal 3:13 (Christ
  became a curse for us). The moral complexity is not resolved by allegory but
  is honestly named.
- Esau's bitter cry (vv34-38): Heb 12:16-17 is the NT reading — a warning
  about despising the sacred for the immediate and then finding no repentance.
  The irrevocability of the blessing (v33 "indeed he will be blessed") connects
  to Rom 11:29 (God's gifts and call are irrevocable).
- v29 blessing language: the full Abrahamic covenant blessing of 12:3 transmitted
  to Jacob, ultimately pointing to Gal 3:14 (the blessing coming to Gentiles
  through Christ).
- Ch28 Bethel vision: John 1:51 is an explicit NT citation — Jesus identifies
  himself as the sulam (stairway/ladder) on which angels ascend and descend.
  This is the chapter's primary Christological connection. The gate of heaven
  (v17) connects to John 10:9; the anointed stone (v18) to 1 Pet 2:4-7; the
  "I am with you" promise (v15) to Matt 28:20.
- Beer Lahai Roi / Bethel geography: Bethel was previously Luz (v19); the
  renaming is significant — the unremarkable becomes the house of God through
  divine encounter, as ordinary human flesh becomes the dwelling of God in the
  incarnation.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 27–28, covering the disputed-blessing
#   narrative (ch27) and the Bethel ladder vision (ch28). The primary NT anchor
#   is John 1:51 (Jesus as the sulam); secondary anchors are Gal 3:13 (curse-
#   bearing), Heb 12:16-17 (Esau's failed repentance), and Matt 28:20 (divine
#   accompaniment promise of v15).
# CHANGE? If data/commentary/mkt-christ/genesis.json structure changes, update
#   load_comm/save_comm in Z_COMMENTARY_SCRIPT_GUIDE.md accordingly.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('27',{})), len(d.get('28',{})))" should print "46 22".

NEW_DATA = {
"27": {
"1": "<p>Isaac old and blind calls Esau &#8212; the setup for the chapter&#8217;s central irony: the father who cannot see will give a blessing to the son he cannot see clearly. Isaac&#8217;s physical blindness mirrors the spiritual misalignment of his intention (to bless Esau) with the divine oracle already given to Rebekah (25:23 &#8212; &#8220;the older will serve the younger&#8221;). The God who works through the blind, the barren, the unexpected, and the outcast is the God who, in Christ, chooses &#8220;the foolish things of the world to shame the wise&#8221; (1 Cor 1:27). Divine purpose advances through human limitation.</p>",
"2": "<p>&#8220;I am now an old man and don&#8217;t know the day of my death.&#8221; Isaac&#8217;s awareness of his own mortality drives the urgency of the blessing. The blessing is a covenant transmission that must occur before death &#8212; it cannot wait. This urgency is the urgency of the covenant itself: the promise must be passed on. The death-awareness that triggers the blessing points forward to the one whose death is itself the means of blessing: the cross of Christ is the moment at which the fullness of the Abrahamic covenant blessing is transmitted to all who receive it (Gal 3:13&#8211;14).</p>",
"3": "<p>Esau&#8217;s hunting weapons &#8212; the implements of his mastery, the skills by which he seeks to earn the blessing through provision. The contrast with Jacob is the contrast between the one who tries to merit the blessing through performance and the one who receives it through grace. The covenant blessing is not earned by hunting skill; it is given by divine promise. Paul in Rom 9:11&#8211;12 makes exactly this point: Isaac&#8217;s twin sons were differentiated &#8220;not by works but by him who calls&#8221; &#8212; before either had done anything to earn or lose the covenant promise.</p>",
"4": "<p>&#8220;So that I may give you my blessing before I die.&#8221; The anticipated deathbed blessing &#8212; in ANE culture, the spoken blessing of a dying patriarch carried legal and spiritual weight that could not be rescinded (cf. v33 &#8212; &#8220;indeed he will be blessed!&#8221;). The binding power of the spoken covenant word is the power that underlies all of Scripture&#8217;s promises. 2 Cor 1:20 &#8212; &#8220;for no matter how many promises God has made, they are &#8216;Yes&#8217; in Christ.&#8221; The patriarch&#8217;s irrevocable spoken blessing is the type of the irrevocable divine promise that Christ secures.</p>",
"5": "<p>Rebekah was listening. She has not forgotten the oracle she received during the difficult pregnancy (25:22&#8211;23) &#8212; that the older would serve the younger. She acts as the one who knows the divine purpose and works to ensure it is fulfilled. Whether her method is commendable is not the narrative&#8217;s focus; what the narrative shows is that the oracle of 25:23 will not be thwarted by Isaac&#8217;s intention to bless Esau. Rom 9:11 &#8212; &#8220;God&#8217;s purpose in election&#8221; stands, not depending on human cooperation or human opposition.</p>",
"6": "<p>Rebekah passes on the overheard conversation to Jacob &#8212; the secret disclosed, the window of opportunity named. The urgency of the moment. The covenant purpose that has been held in tension since 25:23 now moves toward fulfillment through Rebekah&#8217;s knowledge and action. The messy instrumentality of human planning &#8212; eavesdropping, deception, cooking &#8212; is the vehicle through which the divine covenant purpose advances. God&#8217;s providence is not sanitized; it works through genuinely human (and morally complex) situations to accomplish its purposes.</p>",
"7": "<p>Isaac intends the blessing to be given &#8220;in the presence of the LORD before I die.&#8221; The covenantal solemnity of the act is emphasized: this is not merely a father&#8217;s preference but a blessing with divine witness. The divine witness to the blessing is the reason it cannot be recalled (v33). The solemnity of the covenant blessing and its binding character before God points to the new covenant, which is also a covenant made in the divine presence, sealed by divine witness: Heb 9:15 &#8212; &#8220;Christ is the mediator of a new covenant&#8221; &#8212; made in the presence of God and sealed by Christ&#8217;s own blood.</p>",
"8": "<p>&#8220;Listen carefully and do what I tell you.&#8221; Rebekah&#8217;s instruction to Jacob to trust and obey. The narrative does not present this as moral advice &#8212; it is the mother&#8217;s urgent direction in a moment of covenant crisis. The obedience Rebekah requires is the obedience of a son to his mother&#8217;s wisdom. The pattern of a son obediently following the guidance of one who knows the Father&#8217;s purpose points, at a structural level, to the Son who does the Father&#8217;s will: &#8220;I seek not to please myself but him who sent me&#8221; (John 5:30). But the analogy must not be forced &#8212; Jacob&#8217;s obedience here involves deception, which Christ&#8217;s does not.</p>",
"9": "<p>&#8220;Two choice young goats&#8221; &#8212; two goats for the preparation. The detail invites comparison with the two goats of Yom Kippur (Lev 16:5&#8211;10): one killed as a sin offering, one sent into the wilderness bearing the sins of the people. Jacob uses two goats to obtain the blessing; the Levitical system uses two goats to deal with the sin that disqualifies people from blessing. The atoning work that clears the path to divine blessing is the work Christ accomplishes: &#8220;Christ, our Passover lamb, has been sacrificed&#8221; (1 Cor 5:7). The goats of ch27 and the goats of Lev 16 share the same covenant logic &#8212; substitutionary action making blessing possible.</p>",
"10": "<p>&#8220;Take it to your father to eat, so that he may give you his blessing before he dies.&#8221; The substitution enacted: Jacob brings what Esau was supposed to bring; Jacob presents himself as Esau; Jacob receives what was intended for Esau. The substitutionary structure of the episode &#8212; one standing in another&#8217;s place, presenting another&#8217;s identity, receiving another&#8217;s due &#8212; is the structure that Paul articulates in 2 Cor 5:21: &#8220;God made him who had no sin to be sin for us, so that in him we might become the righteousness of God.&#8221; Christ stands in our place before the Father and receives our due (judgment); we stand in Christ&#8217;s place and receive his due (blessing).</p>",
"11": "<p>&#8220;My brother Esau is a hairy man while I have smooth skin.&#8221; Jacob&#8217;s recognition of the fundamental difference between himself and Esau &#8212; the difference that makes the substitution dangerous. He cannot naturally pass for his brother. The smooth-skinned Jacob must be covered to appear like the hairy Esau. The covering of our true nature so that we may present a different identity before the Father &#8212; this is the grace of imputed righteousness. We cannot naturally stand in the presence of God&#8217;s holiness; we must be covered (Gal 3:27 &#8212; &#8220;all of you who were baptized into Christ have clothed yourselves with Christ&#8221;).</p>",
"12": "<p>&#8220;I would appear to be tricking him and would bring down a curse on myself rather than a blessing.&#8221; Jacob&#8217;s fear of bearing the curse he does not deserve &#8212; the curse intended for deceivers. Gal 3:13 &#8212; &#8220;Christ redeemed us from the curse of the law by becoming a curse for us, for it is written: &#8216;Cursed is everyone who is hung on a tree.&#8217;&#8221; Jacob fears becoming a curse-bearer; Christ voluntarily becomes the curse-bearer so that those who are in him need not bear it. The fear expressed in v12 is exactly the fear that the atonement resolves: the curse falls not on those who receive the blessing by grace, but on the one who bears it willingly.</p>",
"13": "<p>&#8220;Let the curse fall on me. Just do what I say.&#8221; Rebekah&#8217;s offer to bear the curse on herself so that Jacob can receive the blessing without penalty. This is genuine maternal sacrifice &#8212; she will absorb the consequence so her son can proceed. The offer of curse-substitution that Rebekah makes (without being able to fulfill it) is the offer that Christ actually fulfills. Gal 3:13 &#8212; he became a curse for us; Isa 53:4&#8211;5 &#8212; he took up our pain and bore our suffering. The offer of substitutionary curse-bearing that Rebekah makes is the type of the one who actually stands in the breach.</p>",
"14": "<p>Jacob obeys and brings the goats; Rebekah prepares the meal. The preparation is careful and deliberate &#8212; exactly right, exactly what the father likes. The gift presented to the father must be perfect &#8212; the right quality, the right preparation. The Levitical offering system has the same requirement: &#8220;without defect&#8221; (Exod 12:5; Lev 1:3). The careful preparation that Rebekah performs so the father&#8217;s taste cannot tell the difference points to the offering that Christ makes &#8212; the one offering that perfectly satisfies the Father&#8217;s requirement (Heb 10:14 &#8212; &#8220;by one sacrifice he has made perfect forever those who are being made holy&#8221;).</p>",
"15": "<p>Rebekah dressed Jacob in Esau&#8217;s best clothes &#8212; the most prized garments of the firstborn son, the garments that carry the smell of the field and the hunter. Jacob is clothed in another&#8217;s identity to receive another&#8217;s blessing. The garment-and-identity theme runs through Scripture: Joseph&#8217;s coat of many colors (37:3), the high priest&#8217;s garments (Exod 28), the robe of righteousness (Isa 61:10). Gal 3:27 &#8212; &#8220;all of you who were baptized into Christ have clothed yourselves with Christ.&#8221; Believers receive the Father&#8217;s blessing not in their own identity but clothed in Christ&#8217;s &#8212; wearing the garments of the firstborn Son, bearing his &#8220;smell&#8221; before the Father.</p>",
"16": "<p>Rebekah covered Jacob&#8217;s hands and smooth neck with goatskins &#8212; the animal skin covering that transforms his apparent identity. The animal skin covering echoes 3:21, where God himself clothed Adam and Eve with animal skins &#8212; the first covering of shame, which required the death of an animal. The goatskin covering of Jacob&#8217;s hands is both a deception and a type: the hands that receive the blessing are covered with the skin of a dead animal, as the sinner&#8217;s approach to God requires the covering provided by a death. Heb 9:22 &#8212; &#8220;without the shedding of blood there is no forgiveness.&#8221;</p>",
"17": "<p>Rebekah handed Jacob the food and bread. The son comes to the father bearing the gift that will unlock the blessing &#8212; but it is not his own provision; it was prepared by his mother with the goats from the family flock. The gift Jacob presents is entirely derivative &#8212; he did not hunt it, he did not prepare it; he merely carries it. The righteousness that believers present before the Father is similarly derivative: &#8220;not having a righteousness of my own that comes from the law, but that which is through faith in Christ &#8212; the righteousness that comes from God on the basis of faith&#8221; (Phil 3:9). We carry a gift we did not produce.</p>",
"18": "<p>Jacob comes to his father and says &#8220;my father.&#8221; The approach to the father &#8212; &#8220;my father&#8221; &#8212; is the language of sonship. The one who approaches is a son approaching a father for the covenant blessing. The NT pattern of approaching the Father through Christ uses the same relational language: &#8220;because you are his sons, God sent the Spirit of his Son into our hearts, the Spirit who calls out, &#8216;<em>Abba</em>, Father&#8217;&#8221; (Gal 4:6). The &#8220;my father&#8221; that Jacob speaks is the &#8220;Abba, Father&#8221; that believers speak through the Spirit &#8212; the language of adopted sonship that the blessing creates.</p>",
"19": "<p>&#8220;I am Esau your firstborn.&#8221; The lie at the center of the narrative &#8212; Jacob claims an identity that is not his own in order to receive a blessing that belongs to another. The moral complexity is real and must not be flattened. What the narrative ultimately shows is that the blessing belongs to Jacob by divine appointment (25:23), not by human merit or deception. The deception is the human mechanism; the divine decree is the underlying reality. The NT reads this not as commending deception but as demonstrating that &#8220;God&#8217;s purpose in election&#8230; depends not on human will or exertion, but on God who calls&#8221; (Rom 9:11&#8211;12).</p>",
"20": "<p>&#8220;The LORD your God gave me success.&#8221; Jacob, while deceiving his father, speaks a theologically true statement: the LORD has indeed given him success in obtaining the materials for the blessing. The ironic truth-within-deception is a narrative device that names the real agent behind the scene. Whatever the moral assessment of Jacob&#8217;s methods, the text insists that divine providence is at work. Acts 2:23 &#8212; Christ was &#8220;handed over to you by God&#8217;s deliberate plan and foreknowledge&#8221; &#8212; similarly names divine purpose within human wrongdoing. Providence is not contaminated by the messiness of its human instruments.</p>",
"21": "<p>&#8220;Come near so I can touch you.&#8221; Isaac&#8217;s test &#8212; he is suspicious because the voice is wrong. He relies on touch to confirm identity. The covenant blessing depends on the father&#8217;s recognition of the son. The test of touch is fooled; the test of voice is not (v22 &#8212; &#8220;the voice is the voice of Jacob&#8221;). In the NT, the voice is the reliable identifier: &#8220;my sheep listen to my voice; I know them, and they follow me&#8221; (John 10:27). The deception that works through covering the body fails at the level of the voice &#8212; pointing to the truth that genuine identity is known through the word, not the appearance.</p>",
"22": "<p>&#8220;The voice is the voice of Jacob, but the hands are the hands of Esau.&#8221; The moment of discord between two senses &#8212; voice and touch tell different stories. Isaac proceeds on the basis of touch, which is deceived; the voice, which is not deceived, is overridden. The voice is the true identifier in the OT (the voice of the LORD at Sinai; the still small voice to Elijah) and in the NT (John 10:27 &#8212; &#8220;my sheep listen to my voice&#8221;). The voice that is authentically Jacob is the truth that the disguise cannot fully conceal &#8212; and it is the voice that the sheep of Christ&#8217;s flock ultimately recognize and follow.</p>",
"23": "<p>Isaac did not recognize Jacob because his hands were hairy like Esau&#8217;s, and he proceeded to bless him. The blessing proceeds based on an appearance &#8212; on what seemed to be the case under Isaac&#8217;s limited perception. The God who sees truly &#8212; who knows Jacob&#8217;s heart, who gave the oracle of 25:23 &#8212; is not deceived by the surface. The covenant blessing is given according to the divine knowledge, even if Isaac&#8217;s human perception is circumvented. 1 Sam 16:7 &#8212; &#8220;the LORD does not look at the things people look at. People look at the outward appearance, but the LORD looks at the heart&#8221; &#8212; the divine sight that goes beyond surface appearance to true identity.</p>",
"24": "<p>&#8220;Are you really my son Esau?&#8221; Isaac&#8217;s lingering doubt, and Jacob&#8217;s unambiguous &#8220;I am.&#8221; The repetition of the lie &#8212; Jacob does not hedge or qualify. The narrative presents this without moral commentary; the reader is left with the discomfort. The blessing that comes through Jacob&#8217;s lie is genuinely the covenant blessing, regardless of the means. This is the profound mystery at the heart of the passage: God&#8217;s covenant purpose advances through and despite human falsehood. Rom 3:3&#8211;4 &#8212; &#8220;their unfaithfulness nullify God&#8217;s faithfulness? Not at all!&#8221; The covenant purpose is more durable than the moral failures of its human instruments.</p>",
"25": "<p>The father ate and drank &#8212; the covenant meal before the blessing. Eating and drinking together &#8212; the covenant ratification meal &#8212; is the pattern from the Sinai covenant (Exod 24:11 &#8212; &#8220;they saw God, and they ate and drank&#8221;) through the Last Supper (Matt 26:26&#8211;28 &#8212; &#8220;eat&#8230; drink&#8230; my blood of the covenant&#8221;). The meal that accompanies the patriarchal blessing is the type of the covenant meal that seals and sustains the new covenant community. The eating and drinking before the blessing becomes, in the NT, the eating and drinking that the blessing makes possible.</p>",
"26": "<p>&#8220;Come here, my son, and kiss me.&#8221; The kiss before the blessing &#8212; the expression of paternal affection and covenant intimacy. The father draws the son near before pronouncing the blessing. The parable of the prodigal son (Luke 15:20) echoes this gesture: &#8220;while he was still a long way off, his father saw him and was filled with compassion for him; he ran to his son, threw his arms around him and kissed him.&#8221; The covenant Father&#8217;s movement toward the returning son &#8212; the kiss as the sign of restoration &#8212; is the NT amplification of the intimacy that the patriarchal blessing creates.</p>",
"27": "<p>&#8220;Ah, the smell of my son is like the smell of a field that the LORD has blessed!&#8221; Isaac smells the garments of Esau that Jacob wears &#8212; the smell of the field, of wild game, of the outdoors &#8212; and it prompts the blessing. The father&#8217;s recognition of &#8220;my son&#8221; through the garments he wears is the image of God recognizing believers as his own through the righteousness of Christ in which they are clothed. Isa 61:10 &#8212; &#8220;he has clothed me with garments of salvation and arrayed me in a robe of his righteousness.&#8221; The smell of the field &#8212; the righteousness of the firstborn Son &#8212; is what the Father recognizes and delights in when he looks at those who are clothed with Christ.</p>",
"28": "<p>&#8220;May God give you heaven&#8217;s dew and earth&#8217;s richness &#8212; an abundance of grain and new wine.&#8221; The material covenant blessing &#8212; agricultural fertility and abundance &#8212; is the type of the spiritual abundance of the new covenant. Eph 1:3 &#8212; &#8220;blessed&#8230; with every spiritual blessing in Christ.&#8221; The &#8220;grain and new wine&#8221; of the patriarchal blessing becomes the &#8220;bread and cup&#8221; of the Lord&#8217;s Table &#8212; the earthly blessings of the old covenant transformed into the sacramental signs of the new. The covenant abundance promised here is the foretaste of the messianic banquet (Isa 25:6; Rev 19:9) that Christ hosts.</p>",
"29": "<p>&#8220;May nations serve you and peoples bow down to you&#8230; May those who curse you be cursed and those who bless you be blessed.&#8221; The full transmission of the Abrahamic covenant blessing (12:3) to Jacob. This is the blessing that Paul in Gal 3:14 says &#8220;might come to the Gentiles through Christ Jesus.&#8221; The nations-and-peoples scope of v29 is the scope of the Great Commission (Matt 28:19 &#8212; &#8220;all nations&#8221;) and the scope of Rev 5:9 (the Lamb&#8217;s redeemed from &#8220;every tribe and language and people and nation&#8221;). The blessing given to Jacob in the field of Canaan extends, through Christ, to every nation on earth.</p>",
"30": "<p>Jacob had scarcely left when Esau arrived. The near-miss &#8212; a matter of minutes separating the two sons &#8212; emphasizes the irreversibility of the spoken covenant word. Had Esau arrived five minutes earlier, he would have received the blessing. The providential timing &#8212; which from a human perspective looks arbitrary &#8212; is from the divine perspective the working out of the oracle given in 25:23. The timing of covenant fulfillment belongs to the divine appointment (Gal 4:4 &#8212; &#8220;when the fullness of time had come&#8221;). The narrow window of v30 is the fullness of time that has come and cannot be recalled.</p>",
"31": "<p>Esau presents his game and asks for the blessing &#8212; the obedient son fulfilling what he was asked to do, arriving too late. The tragedy of Esau is the tragedy of doing the right thing at the wrong time &#8212; after the covenant moment has passed. Heb 12:17 &#8212; Esau &#8220;was rejected. Even though he sought the blessing with tears, he could not change what he had done.&#8221; The warning in Hebrews is about the &#8220;today&#8221; of Ps 95:7 &#8212; &#8220;today, if you hear his voice, do not harden your hearts&#8221; &#8212; the covenant moment that has its own deadline.</p>",
"32": "<p>&#8220;Who are you?&#8221; Isaac&#8217;s question now has tragic weight &#8212; the father who could not recognize the wrong son now genuinely cannot place the right one. The disorientation of Isaac &#8212; &#8220;who are you?&#8221; &#8212; is the disorientation of a world in which the covenant blessing has been transmitted to an unexpected recipient. The ones who expected to receive the blessing of Abraham by right of birth (Esau, and later Israel&#8217;s religious establishment) are displaced by those who receive it by divine appointment and grace &#8212; the pattern that Paul traces through the OT in Romans 9&#8211;11.</p>",
"33": "<p>&#8220;Isaac trembled violently&#8230; I blessed him &#8212; and indeed he will be blessed!&#8221; The irrevocability of the covenant blessing is the theological center of the chapter. Isaac trembles not with anger but with the recognition that he has spoken the word of God &#8212; and what God has blessed cannot be unblessed. Num 23:20 &#8212; &#8220;he has blessed, and I cannot change it.&#8221; Rom 11:29 &#8212; &#8220;God&#8217;s gifts and his call are irrevocable.&#8221; The covenant promises in Christ are similarly irrevocable &#8212; &#8220;for no matter how many promises God has made, they are &#8216;Yes&#8217; in Christ&#8221; (2 Cor 1:20). Isaac&#8217;s trembling is the recognition of divine binding power in the covenant word.</p>",
"34": "<p>Esau&#8217;s loud and bitter cry &#8212; the grief of the displaced. The intensity of Esau&#8217;s anguish is real and the narrative does not minimize it. Heb 12:17 &#8212; &#8220;afterward, as you know, when he wanted to inherit this blessing, he was rejected. Even though he sought the blessing with tears, he could not change what he had done.&#8221; The Hebrews warning uses Esau as the paradigmatic example of the danger of despising the sacred in the present (the birthright sold for a meal, 25:34) and finding too late that the moment of blessing cannot be recalled. The bitter cry of v34 is the sound of the &#8220;today&#8221; that was squandered (Heb 3:13).</p>",
"35": "<p>&#8220;Your brother came deceitfully and took your blessing.&#8221; Isaac&#8217;s honest naming of what happened &#8212; the blessing was taken through deception. The narrative does not redescribe Jacob&#8217;s deception as anything other than what it was. The moral complexity of how the covenant blessing was transmitted &#8212; through deception &#8212; is part of what makes the Abrahamic covenant history so honest about human failure as the backdrop of divine grace. The blessing stands despite the means of its transmission, just as the covenant promise stands despite the failures of all its human bearers. Rom 5:20 &#8212; &#8220;where sin increased, grace increased all the more.&#8221;</p>",
"36": "<p>&#8220;Isn&#8217;t he rightly named Jacob?&#8221; &#8212; <em>yaʿăqōb</em>, the one who &#8220;grasps the heel&#8221; or &#8220;supplants.&#8221; Esau reads Jacob&#8217;s name as characterological destiny: he is a deceiver by nature. The name Jacob will be changed to Israel (32:28) &#8212; from &#8220;supplanter&#8221; to &#8220;one who strives with God.&#8221; The name-change that God gives Jacob marks the transformation that grace works: not elimination of the past but re-naming that redefines identity. Christ gives new names to those who overcome (Rev 2:17; 3:12) &#8212; the renaming that belongs to those who have encountered him.</p>",
"37": "<p>&#8220;I have made him lord over you and have made all his relatives his servants.&#8221; The terms of the blessing already spoken cannot be recalled &#8212; the hierarchy of Jacob-over-Esau is declared. The covenant structure that places the younger over the older (Joseph over his brothers, David over Saul, Christ as the &#8220;last Adam&#8221; who surpasses the first, 1 Cor 15:45) is the recurrent pattern of divine election overturning natural expectation. &#8220;So what can I possibly do for you?&#8221; &#8212; Isaac&#8217;s helplessness before the irrevocable covenant word. The word of blessing, once spoken, stands.</p>",
"38": "<p>Esau wept aloud. Heb 12:17 names this: &#8220;he sought the blessing with tears&#8221; &#8212; tears of genuine grief, but grief that comes too late. The question the author of Hebrews wants readers to ask is: &#8220;am I like Esau &#8212; have I been treating what is sacred as disposable, and will I find the moment of blessing has passed?&#8221; The warning is not about a fixed divine rejection of Esau as a person (God blesses Ishmael and Esau in other ways) but about the specific covenant blessing that cannot be transferred once the moment has closed. The urgency of the gospel invitation carries the weight of this warning.</p>",
"39": "<p>Esau&#8217;s blessing &#8212; &#8220;away from the earth&#8217;s richness, away from the dew of heaven.&#8221; The mirror-image diminishment of Jacob&#8217;s blessing (v28) &#8212; what Jacob receives in abundance, Esau receives in lack. The structure of the two blessings is the structure of the two outcomes: those who receive the covenant blessing in Christ inherit all spiritual blessings (Eph 1:3); those who stand outside the covenant face the corresponding lack. The poetic structure of v39 as the negative of v28 makes the contrast between covenant inclusion and exclusion vivid.</p>",
"40": "<p>&#8220;You will live by the sword and will serve your brother. But when you grow restless, you will throw his yoke from off your neck.&#8221; The partial and temporary reversal &#8212; Esau&#8217;s descendants (Edom) will eventually break free of Israel&#8217;s dominion. 2 Kgs 8:20&#8211;22 records the fulfillment: Edom successfully rebelled against Judah. The &#8220;yoke from off your neck&#8221; is the partial escape from covenant subordination &#8212; but the ultimate horizon of all nations bowing before Christ (Phil 2:10&#8211;11) remains. Temporary escapes from the covenant order are the pattern of history before the final submission of all things to Christ.</p>",
"41": "<p>Esau&#8217;s murderous intent against Jacob &#8212; the elder plotting to kill the younger who has received the covenant blessing. This is the Cain-and-Abel pattern extended: the displaced one seeks to destroy the chosen one. The hatred of the world for those who have received the covenant blessing runs through Scripture: Joseph sold by his brothers, David hunted by Saul, Israel persecuted in exile, the prophets killed, and ultimately Christ crucified by the religious establishment. John 15:18&#8211;19 &#8212; &#8220;if the world hates you, keep in mind that it hated me first.&#8221; Jacob&#8217;s exile begins for the same reason as Abel&#8217;s death: the chosen one is not safe among the displaced.</p>",
"42": "<p>Rebekah is told of Esau&#8217;s plan and sends word to Jacob &#8212; the warning that enables the exile. The one who arranged the blessing now arranges the escape from its consequences. The covenant purpose is protected by those who know it and act to preserve it. The angel who warns Joseph to flee to Egypt (Matt 2:13) follows the same pattern: the covenant heir warned and sent into exile by those who perceive the threat. The protective warning that Rebekah sends Jacob is the type of the divine warnings that preserve the covenant line.</p>",
"43": "<p>&#8220;Flee at once to my brother Laban in Haran.&#8221; The exile of the covenant heir &#8212; Jacob must leave the land of promise to escape destruction. The pattern of exile-and-return shapes the covenant narrative: Abraham left Ur, went to Egypt, returned to Canaan; Jacob will leave, work for Laban, and return; Israel will be exiled to Egypt and return; the exiles will go to Babylon and return. The flight to Haran is the next iteration of the pattern that culminates in Jesus&#8217; flight to Egypt (Matt 2:13&#8211;15) and return &#8212; &#8220;out of Egypt I called my son&#8221; (Hos 11:1).</p>",
"44": "<p>&#8220;Stay with him for a while until your brother&#8217;s fury subsides.&#8221; The &#8220;little while&#8221; that Rebekah expects will last twenty years (ch29&#8211;31). The exile that seems brief stretches long &#8212; the pattern of the people of God living in a &#8220;little while&#8221; of waiting that feels much longer. John 16:16&#8211;22 &#8212; &#8220;in a little while you will see me no more, and then after a little while you will see me&#8221; &#8212; the disciples&#8217; waiting between cross and resurrection, and the church&#8217;s waiting between resurrection and return, are both &#8220;a little while&#8221; that tests patience and faith.</p>",
"45": "<p>&#8220;Why should I lose both of you in one day?&#8221; Rebekah&#8217;s pragmatic grief &#8212; if Esau kills Jacob and is then executed for it, she loses both sons. The covenant mother protecting both sons, even the displaced one. The concern for the wholeness of the family &#8212; even the antagonist &#8212; mirrors the divine concern that none be lost: &#8220;the Lord&#8230; is patient with you, not wanting anyone to perish, but everyone to come to repentance&#8221; (2 Pet 3:9). Rebekah will never see Jacob again, though she does not know it. The exile she arranges for Jacob&#8217;s protection removes him from her own presence permanently.</p>",
"46": "<p>Rebekah&#8217;s complaint about the Hittite wives &#8212; the frame narrative that gives Isaac a reason to send Jacob to Paddan Aram (ch28:1&#8211;2). The covenant concern about the purity of the line &#8212; not ethnic purity but covenant continuity &#8212; is the same concern that animated Abraham&#8217;s charge in ch24: the bride for the covenant son must come from within the family of the promise, not from the Canaanites among whom they live. The concern of v46 is the concern that guarantees Jacob will go to find a wife and will encounter God at Bethel on the way.</p>"
},
"28": {
"1": "<p>Isaac calls Jacob and blesses him &#8212; this time openly, knowingly, explicitly. The blessing that was obtained by deception in ch27 is now ratified in the clear light of Isaac&#8217;s full awareness. Isaac knows he is blessing Jacob and commands him to go to Paddan Aram. The twice-blessed Jacob &#8212; once by deception, once by explicit command &#8212; is doubly confirmed as the covenant heir. The covenant God&#8217;s election of Jacob over Esau is now also the conscious intention of the covenant father, not merely the result of deception.</p>",
"2": "<p>&#8220;Go to the house of your mother&#8217;s father Bethuel. Take a wife from among the daughters of Laban.&#8221; The instruction to seek a wife from within the covenant family &#8212; echoing Abraham&#8217;s charge to his servant in ch24. The continuity of the covenant concern: the bride for the covenant son must not come from the Canaanite world but from within the extended covenant family. The spiritual application is the NT call to the church: the bride of Christ is gathered from within the reach of the covenant promise, not conformed to the surrounding world (Rom 12:2).</p>",
"3": "<p>&#8220;May God Almighty (<em>ʾēl šadday</em>) bless you and make you fruitful and increase your numbers until you become a community of peoples.&#8221; The Abrahamic blessing (17:1&#8211;6 &#8212; where <em>ʾēl šadday</em> first appears) now passes explicitly to Jacob with the same divine name and the same fruitfulness promise. The &#8220;community of peoples&#8221; (<em>qehal ʿammîm</em>) anticipates the church as the gathered assembly of peoples from every nation. The fruitfulness promised to Jacob &#8212; &#8220;be fruitful and multiply&#8221; (cf. 1:28; 9:1) &#8212; is the covenant mandate that Christ extends in the Great Commission: &#8220;go and make disciples of all nations&#8221; (Matt 28:19).</p>",
"4": "<p>&#8220;May he give you and your descendants the blessing given to Abraham, so that you may take possession of the land.&#8221; The explicit Abrahamic covenant blessing transmitted to Jacob &#8212; the blessing that Gal 3:14 says &#8220;might come to the Gentiles through Christ Jesus.&#8221; The land promise is the type of the new creation inheritance that Christ secures (1 Pet 1:4 &#8212; &#8220;an inheritance that can never perish, spoil or fade&#8221;). The &#8220;land where you now reside as a foreigner&#8221; is the resident-alien condition of the covenant people in the present age &#8212; 1 Pet 2:11 &#8212; &#8220;dear friends, I urge you, as foreigners and exiles, to abstain from sinful desires.&#8221;</p>",
"5": "<p>Isaac sent Jacob away and he went. The departure of the covenant heir into exile &#8212; the journey to Paddan Aram that will last twenty years and will define Jacob&#8217;s life. The exiling of the covenant heir is the recurring pattern: Abraham left Ur, Joseph went to Egypt, Moses fled to Midian, David fled from Saul, Elijah fled from Jezebel, the nation went to Babylon. The exile of Jesus (Matt 2:13&#8211;15) is the culmination of the pattern. The covenant heir is preserved through exile and strengthened for return.</p>",
"6": "<p>Esau learned that Isaac had blessed Jacob and sent him to Paddan Aram to find a wife &#8212; and commanded him not to marry a Canaanite woman. Esau&#8217;s awareness of what Jacob has received and been commanded is the awareness of the one who stands outside the primary covenant purpose. The observation of the covenant blessing and its conditions from the outside is Esau&#8217;s position throughout &#8212; near enough to see, not included in the primary line. The &#8220;outsider who observes but does not fully participate&#8221; is a warning figure in the NT: the servant who knows the master&#8217;s will but does not do it (Luke 12:47).</p>",
"7": "<p>&#8220;Jacob had obeyed his father and mother and had gone to Paddan Aram.&#8221; Jacob&#8217;s obedience to both parents &#8212; a detail the narrative notes as significant. The one who obtained the blessing by deception (not a paradigm of obedience) now obeys his father&#8217;s explicit command. The obedience that follows the covenant blessing is the pattern of the Christian life: the blessing received by grace produces obedience as its fruit. Eph 2:8&#8211;10 &#8212; &#8220;for it is by grace you have been saved, through faith&#8230; created in Christ Jesus to do good works.&#8221; The blessing precedes and enables the obedience.</p>",
"8": "<p>Esau &#8220;realized how displeasing the Canaanite women were to his father Isaac.&#8221; A late realization &#8212; he had already married two Hittite women (26:34) and they caused grief to Isaac and Rebekah (26:35). Esau now understands something about covenant expectations that he has previously disregarded. The belated comprehension of what the covenant demands &#8212; after the key decisions have already been made &#8212; is the pattern of those who pursue religious conformity as a strategy rather than a calling. The attempt to please God by conforming to external expectations without inner transformation is a recurring warning in the NT (Matt 15:8 &#8212; &#8220;these people honor me with their lips, but their hearts are far from me&#8221;).</p>",
"9": "<p>Esau married Mahalath, daughter of Ishmael &#8212; trying to demonstrate covenant loyalty by marrying within the extended Abrahamic family. The attempt is genuine but reveals Esau&#8217;s misunderstanding: covenant membership is not secured by genealogical adjustment but by the grace of divine election. Esau adds to his Canaanite wives rather than replacing them &#8212; a partial attempt at conformity. The pattern of trying to add the covenant onto existing commitments rather than receiving it as a full reorientation is the pattern Paul addresses in Galatia: you cannot add circumcision to Christ; you must choose (Gal 5:2&#8211;4).</p>",
"10": "<p>Jacob left Beersheba and set out for Haran. The covenant heir goes into exile alone &#8212; without household, without servants, without the wealth of his father&#8217;s house. The stone under his head (v11) is his only pillow. The one who has received the covenant blessing goes into the world emptied of earthly support &#8212; the condition in which God&#8217;s presence becomes most vivid. Christ&#8217;s kenotic self-emptying (Phil 2:7 &#8212; &#8220;he made himself nothing&#8221;) is the ultimate form of this pattern. The vulnerable exile who has only the divine promise is the one who meets God most directly.</p>",
"11": "<p>Jacob stopped for the night, took a stone for a pillow, and slept. The stone under his head &#8212; the hard ground of exile. This same stone will become the stone pillar of v18, anointed with oil, set up as a sacred marker. The transformation of the exile&#8217;s bed-stone into the anointed pillar of divine encounter is the transformation that grace works in the ordinary and unremarkable. 1 Pet 2:4&#8211;7 &#8212; &#8220;the stone the builders rejected has become the cornerstone&#8221; &#8212; the rejected stone becomes the most important one. The stone that served as Jacob&#8217;s bed in his vulnerability becomes the stone of divine presence.</p>",
"12": "<p>&#8220;He dreamed of a stairway (<em>sullam</em>) resting on the earth, with its top reaching to heaven, and the angels of God were ascending and descending on it.&#8221; The Bethel vision &#8212; the most explicit Christological image in Genesis outside of 3:15. John 1:51 &#8212; Jesus says directly: &#8220;Very truly I tell you, you will see &#8216;heaven open, and the angels of God ascending and descending on&#8217; the Son of Man.&#8221; Jesus identifies himself as the <em>sullam</em> &#8212; the connection between heaven and earth, the one on whom the angels move. The stairway that Jacob sees is the ladder that Christ is: the meeting point of divine and human, the means of access between heaven and earth that is the incarnation itself.</p>",
"13": "<p>&#8220;I am the LORD, the God of your father Abraham and the God of Isaac.&#8221; The divine self-identification at the top of the ladder. This is the formula that Jesus cites in Matt 22:32 to argue for the resurrection: &#8220;&#8216;I am the God of Abraham, the God of Isaac, and the God of Jacob&#8217; &#8212; he is not the God of the dead but of the living.&#8221; The God who stands at the top of the Bethel ladder &#8212; the God of Abraham, Isaac, and now Jacob &#8212; is the God who is fully revealed in Jesus (John 1:18 &#8212; &#8220;no one has ever seen God, but the one and only Son&#8230; has made him known&#8221;). The stairway on which the divine name is proclaimed is the Son of Man.</p>",
"14": "<p>&#8220;All peoples on earth will be blessed through you and your offspring.&#8221; The Abrahamic covenant promise is renewed with Jacob: the blessing to all peoples through Jacob&#8217;s offspring. Gal 3:16 &#8212; the &#8220;offspring&#8221; (<em>sperma</em>) is singular, pointing to Christ; 3:14 &#8212; &#8220;the blessing given to Abraham might come to the Gentiles through Christ Jesus.&#8221; The &#8220;all peoples&#8221; horizon of v14 is the scope of the Great Commission (Matt 28:19) and the vision of Rev 5:9 (redeemed from every tribe, language, people, and nation). The promise spoken to the exile sleeping on a stone reaches every person on earth through Christ.</p>",
"15": "<p>&#8220;I am with you and will watch over you wherever you go, and I will bring you back to this land. I will not leave you until I have done what I have promised you.&#8221; The divine accompaniment promise &#8212; the Immanuel motif that runs from here to its fullest expression in Christ. Matt 28:20 &#8212; &#8220;I am with you always, to the very end of the age&#8221; &#8212; is the NT form of v15, now spoken not by an angel to a patriarch in a dream but by the risen Christ to his disciples as he ascends. The &#8220;I will not leave you&#8221; of v15 is the &#8220;I will never leave you nor forsake you&#8221; of Heb 13:5, grounded in the divine faithfulness that Christ embodies. The exile is always accompanied.</p>",
"16": "<p>&#8220;Surely the LORD is in this place, and I was not aware of it.&#8221; The divine presence in the unremarkable place &#8212; a wilderness roadside stop, not a temple or a city. The incarnation is the ultimate form of divine presence in the unexpected place: &#8220;he was in the world&#8230; but the world did not recognize him&#8221; (John 1:10); &#8220;the Word became flesh and made his dwelling among us&#8221; (John 1:14). The God who is present in the roadside stone is the God who becomes present in a manger in Bethlehem. Jacob&#8217;s awakening recognition &#8212; &#8220;and I was not aware of it&#8221; &#8212; is the recognition that comes to those who begin to see the divine presence they had previously overlooked.</p>",
"17": "<p>&#8220;How awesome is this place! This is none other than the house of God; this is the gate of heaven.&#8221; The declaration of sacred space &#8212; Bethel as the intersection of divine and human. John 10:9 &#8212; &#8220;I am the gate; whoever enters through me will be saved.&#8221; John 14:6 &#8212; &#8220;I am the way and the truth and the life. No one comes to the Father except through me.&#8221; The &#8220;gate of heaven&#8221; that Jacob names is the meeting-point of divine and human access &#8212; and Jesus identifies himself as this gate. The &#8220;house of God&#8221; (<em>bêt ʾĕlōhîm</em>) that Bethel is named becomes in the NT the church (1 Tim 3:15) and the body of Christ (John 2:21).</p>",
"18": "<p>Jacob set up the stone as a pillar and poured oil on top of it. The anointing of the stone with oil consecrates it &#8212; the oil-anointing is the act that gives the title &#8220;<em>māšîaḥ</em>&#8221; (Messiah, anointed one) its meaning. 1 Pet 2:4&#8211;7 &#8212; Christ as &#8220;the living Stone &#8212; rejected by humans but chosen by God and precious to him&#8221; and &#8220;the cornerstone.&#8221; The stone that Jacob anoints with oil is the type of the anointed Stone that is Christ &#8212; the cornerstone on which the house of God is built. The Bethel stone, consecrated by oil in the wilderness, anticipates the Anointed One consecrated by the Spirit (Luke 3:22; Acts 10:38).</p>",
"19": "<p>&#8220;He called that place Bethel (<em>bêt-ʾēl</em>, house of God), though the city used to be called Luz.&#8221; The renaming: what was the unremarkable &#8220;Luz&#8221; becomes the &#8220;house of God.&#8221; The transformation of the ordinary through divine encounter is the pattern of the incarnation &#8212; the unremarkable Nazareth, the obscure Bethlehem, the ordinary fishermen who become apostles. 1 Cor 1:26&#8211;29 &#8212; God chose &#8220;the foolish things of the world to shame the wise&#8230; the lowly things of this world and the despised things.&#8221; What was Luz becomes Bethel; what was unremarkable becomes the house of God when the divine presence encounters it.</p>",
"20": "<p>Jacob&#8217;s vow &#8212; &#8220;If God will be with me and will watch over me on this journey.&#8221; The conditionality of Jacob&#8217;s vow stands in contrast to the unconditional divine promise of v15 (&#8220;I will not leave you&#8221;). Jacob&#8217;s &#8220;if God will be with me&#8221; is answered by God&#8217;s already-spoken &#8220;I am with you.&#8221; The vow is the response of faith still learning to trust &#8212; conditional where God is unconditional. 2 Cor 1:20 &#8212; &#8220;for no matter how many promises God has made, they are &#8216;Yes&#8217; in Christ.&#8221; All of God&#8217;s promises &#8212; including the promise of v15 &#8212; are &#8220;Yes&#8221; in Christ, unconditionally and without the hedge of Jacob&#8217;s &#8220;if.&#8221;</p>",
"21": "<p>&#8220;So that I return safely to my father&#8217;s household, then the LORD will be my God.&#8221; Jacob&#8217;s conditional commitment &#8212; God will be his God if God keeps his promise. The fragility of Jacob&#8217;s faith is honest: he trusts enough to make a vow but not enough to commit without conditions. The NT calls to unconditional commitment &#8212; &#8220;if anyone would come after me, he must deny himself and take up his cross and follow me&#8221; (Matt 16:24) &#8212; move beyond the conditional devotion of Jacob&#8217;s vow to the full surrender that the new covenant requires. Jacob&#8217;s conditional &#8220;then the LORD will be my God&#8221; will become, through the encounter of 32:24&#8211;30, an unconditional identity-defining relationship.</p>",
"22": "<p>&#8220;This stone that I have set up as a pillar will be God&#8217;s house, and of all that you give me I will give you a tenth.&#8221; The stone-as-house and the tithe-as-response complete the vow. The anointed stone as the house of God &#8212; the prototype of all subsequent temples &#8212; finds its NT fulfillment in Christ as the living temple (John 2:21) and the church as the dwelling place of the Spirit (1 Cor 3:16; Eph 2:19&#8211;22). The tithe &#8212; a tenth of all that God gives &#8212; is the recognition that all things come from God and a portion belongs to him. Heb 7:2&#8211;4 connects tithing to Melchizedek, who prefigures Christ&#8217;s eternal priesthood. The vow of v22 is the response of faith to a grace that has already been given.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch27 verses: {len(existing.get('27', {}))}")
    print(f"  ch28 verses: {len(existing.get('28', {}))}")
    print("Genesis 27–28 mkt-christ written.")

if __name__ == '__main__':
    main()
